const Q_PHYSICS_1990=[{"id": "objective>Physics>1990>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a fundamental unit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Newton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Watt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Joule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Second</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fundamental units are the basic units of measurement defined by the International System of Units (SI) from which other units are derived. <br/>  <br/> Second (s) is the fundamental SI unit of time. <br/>  <br/> Newton (N), Watt (W), and Joule (J) are derived units: <br/>  <br/> Newton = kg·m/s² (unit of force) <br/>  <br/> Watt = J/s (unit of power) <br/>  <br/> Joule = N·m (unit of energy/work) <br/>  <br/> Hence, Second is the fundamental unit among the options.</div>", "topic": "MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}, {"id": "objective>Physics>1990>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car moving with a speed of 90kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span> was brought uniformly to rest by the application of the brakes in 10s. How far did the car travel after the brakes were applied?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">125 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15 km</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Initial speed, u = 90 kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Time taken to stop, t = 10 s <br/> Final speed, v = 0 (since the car comes to rest) <br/>  <br/> Converting speed to ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">90</td><td style=\"text-align:center;\">kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">90×1000<hr size=\"1\" />3600</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25</td><td style=\"text-align:center;\">ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div> <br/> Finding acceleration a: <br/>  <br/> Using equation of motion, <br/>  <br/> v = u + at <br/>  <br/> 0 = 25 + a × 10   <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">⟹  a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">−25<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">−2.5</td><td style=\"text-align:center;\">ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div> <br/> (The negative sign indicates deceleration.) <br/>  <br/> Finding distance traveled s: <br/>  <br/> Using <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ut</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> s = 25 × 10 + 12(−2.5) × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/> s = 250 - 125 = 125 m</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>1990>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle of mass M which is at rest splits up into two. If the mass and velocity of one of the particles are m and v respectively, calculate the velocity of the second particle</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<hr size=\"1\" />M</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Mv<hr size=\"1\" />M - m</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<hr size=\"1\" />M + m</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<hr size=\"1\" />M - m</td></tr></table></div></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We use conservation of momentum because the initial particle was at rest. <br/>  <br/> Initial momentum = 0 <br/>  <br/> Final momentum = momentum of particle 1 + momentum of particle 2 <br/>  <br/> 0 = mv + (M − m)v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  <br/> (M − m)v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = −mv <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">−mv<hr size=\"1\" />M − m</td></tr></table></div> <br/> (The negative sign shows the second particle moves in the opposite direction). <br/>  <br/> So, the magnitude of the velocity is: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<hr size=\"1\" />M − m</td></tr></table></div></div>", "topic": "MOTION: NEWTON'S LAWS OF MOTION"}, {"id": "objective>Physics>1990>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements are correct about an object in equilibrium under parallel forces? i. the total clockwise moments of the forces about any point equals the total anti-clockwise moments about the same point. ii. the total forces in one direction equals the total forces in the opposite direction. iii. the resolved components along the x-axis equals the resolved components along the y-axis.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and ii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, and iii only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For an object in equilibrium under parallel forces: <br/>  <br/> Statement i: Correct. For rotational equilibrium, the sum of clockwise moments about any point must equal the sum of anticlockwise moments about the same point. <br/>  <br/> Statement ii: Correct. For translational equilibrium, the sum of forces in one direction must equal the sum of forces in the opposite direction (net force is zero). <br/>  <br/> Statement iii: Incorrect. Since the forces are parallel, they all act in the same direction (or opposite). Resolving along x and y axes is not necessary; instead, we consider the direction of the forces. For parallel forces, the components along the perpendicular axis are zero, and equilibrium requires balance only along the direction of the forces. <br/>  <br/> Thus, only statements i and ii are correct.</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>1990>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To keep a vehicle moving at a constant speed v, requires power P, from the engine. The force provided by the engine is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<hr size=\"1\" />v</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">v</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pv</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<hr size=\"1\" />v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We know the relation between power, force, and velocity: <br/>  <br/> P = Fv  <br/>  <br/> So, the force is: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<hr size=\"1\" />v</td></tr></table></div></div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>1990>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A stone of mass m kg is held h meters above the floor for 50 s. The work done in joules over this period is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mgh</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mgh<hr size=\"1\" />50</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Work done is defined as force × displacement in the direction of the force. <br/>  <br/> The stone is held stationary (no displacement). <br/>  <br/> Since there is no movement, no work is done, even though a force is applied.</div>", "topic": "WORK, ENERGY AND POWER: WORKDONE"}, {"id": "objective>Physics>1990>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 10 kg rests on a rough inclined plane whose angle of tilt θ is variable. θ is gradually increased until the body starts to slide down the plane at 30°. The coefficient of limiting friction between the body and the plane</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.58</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.87</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We use the condition for limiting equilibrium on an inclined plane: <br/>  <br/> tan θ = μ  <br/>  <br/> where μ = coefficient of limiting friction, and θ = angle at which sliding just begins. <br/>  <br/> Given: <br/>  <br/> θ = 30° <br/>  <br/> So: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">μ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">tan</td><td style=\"text-align:center;\">30°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td><td style=\"text-align:center;\">≈</td><td style=\"text-align:center;\">0.58</td></tr></table></div> <br/> The coefficient of limiting friction = 0.58</div>", "topic": "MOTION: FRICTION"}, {"id": "objective>Physics>1990>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An inclined plane which makes an angle of 30° with the horizontal has a velocity ratio of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.866</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity ratio (VR) of an inclined plane is given by: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">VR</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Distance moved by effort<hr size=\"1\" />Distance moved by load</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />sin θ</td></tr></table></div> <br/> For θ = 30° <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">VR</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />sin 30°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />0.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td></tr></table></div> <br/> Velocity ratio = 2</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>1990>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the length of liquid column in a barometer tube that would support an atmospheric pressure of 102000 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> if the density of the liquid is 2600 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>? [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.75 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.76 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.92 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">39.23 m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We use the barometric relation: <br/>  <br/> P = ρgh  <br/>  <br/> where <br/>  <br/> P = 102000 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/>  <br/> ρ = 2600 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/>  <br/> g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/>  <br/> h = ? <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<hr size=\"1\" />ρg</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">102000<hr size=\"1\" />2600 × 10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.92 m</td></tr></table></div> <br/> The length of the liquid column = 3.92 m</div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>1990>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">40 m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of liquid is mixed with 60 m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of another liquid Q. If the density of P and Q are 1.00 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> and 1.6 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> respectively, what is the density of the mixture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.05 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.30 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.36 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the density of the mixture, we use: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">mixture</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">total mass<hr size=\"1\" />total volume</td></tr></table></div> <br/> For liquid P: <br/>  <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> × V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> = 1.0 × 40 = 40 kg  <br/>  <br/> For liquid Q: <br/>  <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Q</span> = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Q</span> × V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Q</span> = 1.6 × 60 = 96 kg  <br/>  <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">total</span> = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> + m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Q</span> = 40 + 96 = 136 kg  <br/>  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">total</span> = 40 + 60 = 100 m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">mixture</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">136<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.36 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div> <br/> The density of the mixture = 1.36 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "EQUILIBRIUM OF LIQUIDS: RELATIVE DENSITY"}, {"id": "objective>Physics>1990>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The resistances of platinum wire at the ice and steam points are 0.75 &#937; and 1.05 Ω respectively. Determine the temperature at which the resistance of the wire is 0.90 Ω.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">43.0°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.0°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">69.0°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">87.0°C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C - 0<hr size=\"1\" />100 - 0</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.90 - 0.75<hr size=\"1\" />1.05 - 0.75</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.15<hr size=\"1\" />0.30</td></tr></table></div> <br/> 0.30C = 15 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15<hr size=\"1\" />0.30</td></tr></table></div> <br/> ∴ C = 50.0°C</div>", "topic": "TEMPERATURE AND ITS MEASUREMENTS: THERMOMETERS"}, {"id": "objective>Physics>1990>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bar of initial length l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> is heated through a temperature change Δt to a new length I. The linear expansivity, a, of the bar is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><hr size=\"1\" />lΔt</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>Δt</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>(1 + Δt)</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><hr size=\"1\" />l(1 + Δt)</td></tr></table></div></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The formula for linear expansion is: <br/>  <br/> Δl = l − l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = αl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>Δt  <br/>  <br/> Rearranging for α: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">l − l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>Δt</td></tr></table></div></div>", "topic": "THERMAL EXPANSION: SOLIDS"}, {"id": "objective>Physics>1990>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure of a gas when cooled at constant volume will decrease because the molecules</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">collide less frequently with the walls of the container</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have the same average kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">break up into smaller molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in number</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the Kinetic Theory of Gases, the pressure exerted by a gas on the walls of its container is caused by the constant, random collisions of its molecules with the walls. The pressure is a measure of the total force exerted by these collisions over a specific area. <br/>  <br/> When a gas is cooled at a constant volume: <br/>  <br/> Temperature decreases: The temperature of a gas is a measure of the average kinetic energy of its molecules. So, a decrease in temperature means the molecules' average kinetic energy also decreases. <br/>  <br/> Molecules slow down: As the average kinetic energy decreases, the molecules move more slowly on average. <br/>  <br/> Fewer and weaker collisions: Since the molecules are moving slower, they will collide with the walls of the container less frequently and with less force in each collision. <br/>  <br/> The combined effect of less frequent and less forceful collisions results in a decrease in the total force on the walls, which is observed as a decrease in pressure.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>1990>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">1 kg of copper is transferred quickly from boiling water to a block of ice. Calculate the mass of ice melted, neglecting heat loss. [specific heat capacity of copper 400 Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and latent heat of fusion of ice 333 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">67 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">133 g</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat lost = heat gained <br/>  <br/> 1 × 400 × (100 - 0) = m × 333000 <br/>  <br/> 400 × 100 = 333000m <br/>  <br/> 40000 = 333000m <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40000<hr size=\"1\" />333000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.12</td><td style=\"text-align:center;\">kg</td></tr></table></div> <br/> ∴ m = 0.12 × 1000 = 120 g</div>", "topic": "HEAT TRANSFER: LATENT HEAT OF FUSION"}, {"id": "objective>Physics>1990>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following conditions will make water boil at a temperature of 100°C when the atmospheric pressure is 750 mmHg?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the external pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the external pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat more rapidly at the same pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the external pressure by a quarter</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The boiling point of a liquid is the temperature at which its vapor pressure equals the external pressure pushing down on its surface. When the external pressure is the standard atmospheric pressure of 760 mmHg, water boils at 100°C. <br/>  <br/>  <br/> At an atmospheric pressure of 750 mmHg, which is lower than the standard pressure, the water's vapor pressure needs to be lower to reach boiling. This means the water will boil at a temperature below 100°C. <br/>  <br/> Therefore, to make the water boil at exactly 100°C, the external pressure must be increased from 750 mmHg back up to 760 mmHg.</div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>1990>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements are correct? i. land and sea breezes are natural convection currents. ii. convection may occur in liquids or gasses but not in solids. iii. the vacuum in a thermos flask prevents heat loss due to convection only.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and ii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, and iii</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Statement i: \"land and sea breezes are natural convection currents.\" <br/> This statement is correct. Land and sea breezes are a perfect example of natural convection. During the day, land heats up faster than the sea. The air above the land warms, becomes less dense, and rises. Cooler, denser air from the sea flows in to take its place, creating a sea breeze. At night, the process reverses as the land cools faster than the sea. This circulation of air is a form of convection. <br/>  <br/> Statement ii: \"convection may occur in liquids or gasses but not in solids.\" <br/> This statement is correct. Convection is the transfer of heat through the bulk movement of a medium. Since the particles in solids are held in fixed positions and cannot move freely, convection cannot occur. It is a process exclusive to fluids (liquids and gases). <br/>  <br/> Statement iii: \"the vacuum in a thermos flask prevents heat loss due to convection only.\" <br/> This statement is incorrect. The vacuum in a thermos flask prevents heat transfer by both conduction and convection because both of these processes require a material medium (particles) to transfer heat. A vacuum is a space with very few particles, so it effectively stops these two forms of heat transfer. However, it does not stop heat transfer by radiation, which is why thermos flasks also have shiny, silvered surfaces to reflect thermal radiation.</div>", "topic": "HEAT TRANSFER : LAND AND SEA BREEZE~~HEAT TRANSFER : THERMOS FLASK"}, {"id": "objective>Physics>1990>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A light wave of frequency 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> Hz moves through water which has a refractive index of <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">4</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span>. Calculate the wavelength in water if the velocity of light in air is 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.7 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Speed of light in a medium is given by: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">c<hr size=\"1\" />n</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span><hr size=\"1\" /><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">4</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span></td></tr></table></div> <br/> v = 2.25 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−1</span> <br/>  <br/> v = fλ <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.25 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span><hr size=\"1\" />5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span></td></tr></table></div> <br/> ∴ λ = 0.45 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−6</span> m = 4.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−7</span> m</div>", "topic": "LIGHT WAVES"}, {"id": "objective>Physics>1990>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wave disturbance travelling in air enters a medium in which its velocity is less than that in air. Which of the following statements is true about the wave medium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">both the frequency of the wave and the wavelength are decreased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the frequency of the wave is decreased while the wavelength is increased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the frequency of the wave is unaltered while the wavelength is decreased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the frequency of the wave is decreased while the wavelength is unaltered</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a wave travels from one medium to another, its properties can change, but the change follows a consistent set of rules. <br/> 1.\tFrequency is Unaltered: The frequency of a wave is determined by the source that produced it (e.g., a vibrating object). When the wave enters a new medium, the source is still vibrating at the same rate, so the wave's frequency does not change. <br/> 2.\tVelocity and Wavelength Change: The velocity of a wave is determined by the properties of the medium it travels through. The problem states that the wave's velocity decreases. According to the wave equation, which links velocity (v), frequency (f), and wavelength (λ):  <br/> v = fλ <br/> Since the frequency (f) remains constant, if the velocity (v) decreases, the wavelength (λ) must also decrease proportionally to maintain the equality. <br/> This change in velocity and wavelength is what causes phenomena like the bending of light (refraction) as it passes from air into a denser medium like glass or water.</div>", "topic": "SOUND WAVES: PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1990>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Shadows and eclipses result from the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">refraction of light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rectilinear propagation of light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction of light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflection of light</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shadows and eclipses occur because light travels in straight lines. This property is known as the rectilinear propagation of light. When an opaque object blocks light, it creates a shadow because light cannot bend around it (under normal conditions without diffraction). Similarly, eclipses happen when celestial bodies align and block light due to this straight-line path.</div>", "topic": "LIGHT ENERGY: PROPAGATION OF LIGHT"}, {"id": "objective>Physics>1990>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object which is 3 cm high is placed vertically 10 cm in front of a concave mirror. If this object produces an image 40 cm from the mirror, the height of the image is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.75 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.00 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.00 cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We solve using the magnification formula: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span><hr size=\"1\" />h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td></tr></table></div> <br/> Where: <br/>  <br/> u = 10 cm (object distance, taken as positive since it is in front of a concave mirror conventionally) <br/>  <br/> v = 40 cm (image distance) <br/>  <br/> h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 3 cm (object height) <br/>  <br/> h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> = ? (image height) <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4</td></tr></table></div> <br/> So, <br/>  <br/> hi = M × h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 4 × 3 = 12 cm  <br/>  <br/> The height of the image is 12 cm (real and inverted since it's a concave mirror image at positive v).</div>", "topic": "LIGHT WAVES: REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>1990>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boy looks at the image of an object in a plane mirror. He observes two images, a main bright one and the other faint. The observed images result from?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction and interference</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflection and refraction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a boy looks at an object in a plane mirror, the primary image he sees is due to direct reflection of light from the mirror's surface. The faint secondary image, if observed, is likely caused by additional reflections of light within the mirror or from surrounding surfaces. Refraction, diffraction, and interference are not significant factors in this scenario as plane mirrors primarily cause reflection. </div>", "topic": "LIGHT WAVES: REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>1990>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What must be the distance between an object and a converging lens of focal length 20 cm to produce an erect image two times the object height?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">f = 20 cm <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td></tr></table></div> <br/> v = 2u <br/>  <br/> Since the image is erect, it must be virtual, meaning v is negative. <br/>  <br/> So: <br/>  <br/> v = -2u <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />-2u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />2u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 - 1<hr size=\"1\" />2u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2u</td></tr></table></div> <br/> 2u = 20 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />2</td></tr></table></div> <br/> ∴ u = 10 cm</div>", "topic": "LIGHT WAVES: REFRACTION OF LIGHT THROUGH LENSES"}, {"id": "objective>Physics>1990>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a short sighted person, light rays from a point on a very distant object is focused</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in front of the retina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on the retina by a converging lens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">behind the retina by a diverging lens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in front of the retina, a distance 2F from the lens</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Short-sightedness, or myopia, is a common vision condition where a person can see close objects clearly, but distant objects appear blurry. This happens because the eye's focusing power is too strong, or the eyeball is too long. <br/>  <br/> When light rays from a very distant object enter the myopic eye, the lens system brings them to a focus in front of the retina, rather than directly on it. This causes the light to diverge again by the time it reaches the retina, resulting in a blurred image.</div>", "topic": "LIGHT WAVES: REFRACTION OF LIGHT THROUGH LENSES"}, {"id": "objective>Physics>1990>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When light is incident on an object which is magenta in colour, which of the following colour would be absorbed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Red and blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red and green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The color we see when we look at an opaque object is the color of light that it reflects. The other colors of light that are part of the incident white light are absorbed by the object. <br/>  <br/> The primary colors of light are Red, Green, and Blue (RGB). When you mix these three colors of light in equal amounts, you get white light. <br/>  <br/> The color magenta is a secondary color of light, which is created by mixing the primary colors Red and Blue together. Therefore, an object that appears magenta reflects both red and blue light. <br/>  <br/> When white light (which contains Red, Green, and Blue) shines on a magenta object, the object reflects the red and blue light and absorbs the remaining primary color, which is Green.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>1990>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a resonance tube experiment, the effective length of the air column for the first resonance is 20 cm when set into vibration by a tuning fork of frequency 480 Hz. Neglecting and effect, the velocity of sound in air is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">96 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">255 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">340 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">384 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We are solving for the velocity of sound in a resonance tube experiment. <br/>  <br/> Given: <br/>  <br/> Frequency of tuning fork, f = 480 Hz <br/>  <br/> Effective length at first resonance, L = 20 cm = 0.20 m <br/>  <br/> For a resonance tube closed at one end, the first resonance corresponds to the fundamental frequency, where: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td></tr></table></div> <br/> So, <br/>  <br/> λ = 4L = 4 × 0.20 = 0.80 m  <br/>  <br/> Now, velocity of sound: <br/>  <br/> ∴ v = fλ = 480 × 0.80 = 384 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "SOUND WAVE: RESONANCE"}, {"id": "objective>Physics>1990>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organic pipe closed at one end is 80 cm long. Determine the frequency of the fundamental note assuming that the speed of sound in air is 340 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">106 Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">213 Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">318 Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">425 Hz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We are finding the fundamental frequency of an organ pipe closed at one end. <br/>  <br/> Given: <br/>  <br/> Length of pipe: L = 80 cm = 0.80 m <br/>  <br/> Speed of sound: v = 340 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  <br/> For a closed pipe, the fundamental note corresponds to a quarter wavelength: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td></tr></table></div> <br/> So, <br/>  <br/> λ = 4L = 4 × 0.80 = 3.2 m  <br/>  <br/> Now frequency: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">340<hr size=\"1\" />3.2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">106.25 Hz</td></tr></table></div></div>", "topic": "SOUND WAVES: HARMONICS AND OVERTONES"}, {"id": "objective>Physics>1990>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sonometer wire of length 100 cm under a tension of 10 N, has a frequency of 250 Hz. Keeping the length of the wire constant, the tension is adjusted to produce a new frequency of 350 Hz. The new tension is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.1 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.1 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.0 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19.6 N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We are asked to find the new tension in a sonometer wire. <br/>  <br/> Given: <br/>  <br/> Initial length of wire: L = 100 cm (constant) <br/>  <br/> Initial tension: T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10 N <br/>  <br/> Initial frequency: f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 250 Hz <br/>  <br/> New frequency: f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 350 Hz <br/>  <br/> For a sonometer wire of fixed length and mass per unit length, the frequency is: <br/>  <br/> f ∝ &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span>  <br/>  <br/> So: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">350<hr size=\"1\" />250</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />10</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">7<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />10</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> Square both sides <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">49<hr size=\"1\" />25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />10</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">49<hr size=\"1\" />25</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10</td></tr></table></div> <br/> ∴ T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 19.6 N <br/> </div>", "topic": "SOUND WAVES: CALCULATIONS ON SOUND WAVES"}, {"id": "objective>Physics>1990>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the properties of the earth's magnetic field is that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">north pole lies in the northern hemisphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geographic and magnetic meridians coincide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earth's magnetic flux is entirely horizontal at a place where the magnetic dip is zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earth's magnetic flux is entirely vertical at a place where the magnetic dip is zero</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Earth's magnetic field lines are not perfectly parallel to the surface everywhere. The angle that the field lines make with the horizontal is called the magnetic dip or magnetic inclination. <br/>  <br/> At the magnetic equator, the magnetic field lines are parallel to the surface of the Earth. At this location, the magnetic dip angle is zero, and the magnetic flux is entirely horizontal. <br/>  <br/> At the magnetic poles, the magnetic field lines are perpendicular to the surface. At these locations, the magnetic dip angle is 90°, and the magnetic flux is entirely vertical.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : EARTH’S MAGNETIC FIELD"}, {"id": "objective>Physics>1990>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements are true of an insulated charged body carrying positive charge? i. it contains excess positive charges. ii. it creates an electric field. iii. it possesses potential energy. iv. it carries electric current. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and ii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iii and iv</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">i. it contains excess positive charges. This statement is true. An object becomes positively charged when it has lost electrons (negatively charged particles), leaving it with a net surplus of protons (positively charged particles). <br/>  <br/> ii. it creates an electric field. This statement is true. Any object with a net electric charge, whether positive or negative, creates an electric field in the space surrounding it. The field lines point radially outward from a positive charge. <br/>  <br/> iii. it possesses potential energy. This statement is true. A charged body has electric potential energy. This energy is stored in the electric field it creates and represents the work done to accumulate the excess charge on the object against the repulsive forces of the like charges. <br/>  <br/> iv. it carries electric current. This statement is false. Electric current is defined as the flow of electric charge. The term \"insulated\" implies that the charge is confined to the body and is not moving. Therefore, an insulated charged body holds a static charge and does not carry an electric current.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>1990>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a vector?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electric charge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electric field</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electrical potential difference</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electrical capacitance</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A vector is a physical quantity that has both magnitude and direction. A scalar is a physical quantity that has only magnitude. <br/>  <br/> Electric charge: This is a scalar quantity. It has a magnitude (e.g., +5 Coulombs) but no associated direction. <br/>  <br/> Electric field: This is a vector quantity. It is defined as the force per unit charge experienced by a positive test charge at a given point. Since force is a vector, the electric field also has both a magnitude and a direction (pointing away from positive charges and towards negative charges). <br/>  <br/> Electrical potential difference: This is a scalar quantity. It is the work done per unit charge to move a charge between two points in an electric field. Since work and charge are both scalars, the potential difference is also a scalar. <br/>  <br/> Electrical capacitance: This is a scalar quantity. It is a measure of an object's ability to store an electric charge and has no directional component.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>1990>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three cells each of e.m.f. 1.5 V and an internal resistance of 1.0 Ω are connected in parallel across a load resistance of 2.67 Ω. Calculate the current in the load?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.26 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.41 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.79 A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/> E.m.f. of each cell: E = 1.5 V <br/>  <br/> Internal resistance of each cell: r = 1.0 Ω <br/>  <br/> Number of cells in parallel: n = 3 <br/>  <br/> Load resistance: R = 2.67 Ω <br/>  <br/> When identical cells are connected in parallel: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">r<hr size=\"1\" />n</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.0<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.333 Ω</td></tr></table></div> <br/> Total resistance in circuit <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">total</span> = R + r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span>  <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">total</span> = 2.67 + 0.333 = 3.00 Ω  <br/>  <br/> Ohm's law: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">total</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" />3.00</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5 A</td></tr></table></div></div>", "topic": "ELECTRIC CELLS : ARRANGEMENT OF CELLS"}, {"id": "objective>Physics>1990>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a known standard resistor of 2 Ω is connected to the 0.0 cm end of a meter bridge, the balance point is found to be at 55.0 cm. What is the value of the unknown resistor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.10 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.64 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.44 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">27.50 Ω</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the value of the unknown resistor using a meter bridge, we use the principle of the Wheatstone bridge. The balance condition is: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">known</span><hr size=\"1\" /></td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">unknown</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> where: <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">known</span> = 2 Ω is the known resistor, <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">unknown</span> is the unknown resistor, <br/>  <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 55.0 cm is the length from the end where the known resistor is connected to the balance point, <br/>  <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 100 - L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 100 - 55 = 45.0 cm is the length from the balance point to the other end. <br/>  <br/> So, <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">unknown</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">55<hr size=\"1\" />45</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">unknown</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 × 45<hr size=\"1\" />55</td></tr></table></div> <br/> ∴ R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">unknown</span> = 1.64 Ω</div>", "topic": "CURRENT ELECTRICITY : METER BRIDGE"}, {"id": "objective>Physics>1990>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The total energy required to send a unit positive charge round a complete electrical circuit is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potential difference</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electromotive force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrical energy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electromotive force (e.m.f.) is defined as the work done (or energy supplied) per unit positive charge by a source in driving the charge round a complete circuit (including both the external resistance and the internal resistance of the source). <br/>  <br/> Potential difference (p.d.), on the other hand, is the work done per unit charge between two points in the circuit. <br/>  <br/> So the key phrase \"round a complete electrical circuit\" refers specifically to e.m.f.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>1990>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an essential physical property of the wires used for making fuses?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high thermal conductivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low electrical resistivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low melting point</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A fuse wire is a safety device that melts and breaks the circuit when excessive current flows. <br/>  <br/> For this to happen safely and quickly: <br/>  <br/> The melting point must be low, so the fuse wire melts before the wiring or appliances are damaged. <br/>  <br/> High thermal conductivity is not desirable, otherwise the heat would dissipate too quickly and the fuse might not melt in time. <br/>  <br/> Low electrical resistivity is also not desirable, because the fuse needs to generate heat (I²R) when current is high. <br/>  <br/> Density has little to do with its function. <br/>  <br/> Hence, the essential property is a low melting point.</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>1990>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is most suitable for protecting the circuit of 2000 W electric iron connected to a 250 V mains?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">13 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 A</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To determine the correct fuse rating for the electric iron, we first need to calculate the current it draws under normal operating conditions. We can do this using the formula for electrical power: <br/>  <br/> P = VI <br/>  <br/> Where: <br/>  <br/> P is the power (2000 W) <br/>  <br/> V is the voltage (250 V) <br/>  <br/> I is the current (what we need to find) <br/>  <br/> Rearrange the formula to solve for I: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<hr size=\"1\" />V​</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2000 W<hr size=\"1\" />250 V</td><td style=\"text-align:center;\">​=</td><td style=\"text-align:center;\">8</td><td style=\"text-align:center;\">A</td></tr></table></div> <br/> A fuse is a safety device designed to break a circuit if the current becomes dangerously high. The fuse rating must be chosen carefully: <br/>  <br/> It must be equal to or greater than the normal operating current to avoid blowing under regular use. <br/>  <br/> It should be the smallest rating that is still greater than the operating current to provide the best protection against an overload. <br/>  <br/> The calculated operating current is 8 A. Looking at the options: <br/>  <br/> 3 A and 5 A are too small and would blow immediately. <br/>  <br/> 8 A is exactly the operating current. This is risky, as even minor current fluctuations could cause the fuse to blow. <br/>  <br/> 13 A is the next standard fuse rating above 8 A. It provides a safe buffer while still protecting the circuit effectively in case of a fault. Therefore, a 13 A fuse is the most suitable choice.</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>1990>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electrical power is transmitted at a high voltage rather than low voltage because the amount of energy loss is reduced due to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heat dissipation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production of eddy currents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excessive current discharge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excessive voltage distance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Power transmission lines have a certain amount of electrical resistance. When current flows through these wires, energy is lost in the form of heat due to the Joule heating effect. This power loss (Ploss​) is directly proportional to the resistance of the wire (R) and, most importantly, the square of the current (I) flowing through it: <br/>  <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">loss</span> ​= I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R <br/>  <br/> The electrical power being transmitted (P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">supply</span>​) is the product of the voltage (V) and the current (I): <br/>  <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">supply</span> ​= VI <br/>  <br/> To transmit a large amount of power (P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">supply</span>​) over long distances, the current (I) must be minimized to reduce the I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R energy losses. By rearranging the power equation to I = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">supply</span>​/V, we can see that if the voltage (V) is increased, the current (I) must decrease for the same amount of power. Since the energy loss depends on the current squared, even a small reduction in current leads to a significant decrease in power loss. <br/>  <br/> This is why power is transmitted at very high voltages (hundreds of thousands of volts) and then \"stepped down\" by transformers for safe use in homes and businesses.</div>", "topic": "ELECTRICAL ENERGY AND POWER : ELECTRIC POWER TRANSMISSION"}, {"id": "objective>Physics>1990>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A lamp is rated 240 V, 60 W. The resistance of the filament is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">960 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />R</td></tr></table></div> <br/> So, <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />P</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">240<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />60</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">57600<hr size=\"1\" />60</td></tr></table></div> <br/> ∴ R = 960 Ω</div>", "topic": "CURRENT ELECTRICITY : RESISTANCE"}, {"id": "objective>Physics>1990>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 0 - 10 mA galvanometer with a coil resistance of 30 Ω can be converted to a 0 - 10 A ammeter by using</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.03 Ω series resistor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.03 Ω shunt resistor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.99 Ω shunt resistor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.99 Ω series resistor</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = 10 mA = 0.01 A <br/>  <br/> Current required for full-scale deflection of ammeter: <br/>  <br/> I = 10 A  <br/>  <br/> So, most of the current (almost 10 A) must bypass the galvanometer through a shunt resistor. <br/>  <br/> Voltage across galvanometer at full-scale: <br/>  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span>R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = 0.01 × 30 = 0.3 V  <br/>  <br/> This means the shunt resistor must also have 0.3 V across it. <br/>  <br/> Current through the shunt: <br/>  <br/> I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = I - I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = 10 − 0.01 = 9.99 A  <br/>  <br/> Shunt resistance <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.3<hr size=\"1\" />9.99</td><td style=\"text-align:center;\">≈</td><td style=\"text-align:center;\">0.03 Ω</td></tr></table></div></div>", "topic": "ELECTRIC CELLS: SHUNT AND MULTIPLIER"}, {"id": "objective>Physics>1990>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of neutrons contained in the nucleus <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">92</div>", "<div style=\"font-family:Cambria;font-size:17px;\">146</div>", "<div style=\"font-family:Cambria;font-size:17px;\">238</div>", "<div style=\"font-family:Cambria;font-size:17px;\">330</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the number of neutrons in the nucleus <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U: <br/>  <br/> - The mass number A = 238 (total number of protons and neutrons). <br/>  <br/> - The atomic number Z = 92 (number of protons). <br/>  <br/> The number of neutrons N is: <br/>  <br/> N = A - Z = 238 - 92 = 146</div>", "topic": "ELEMENTARY MODERN PHYSICS : ELEMENTARY STRUCTURE OF THE ATOM"}, {"id": "objective>Physics>1990>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What precaution should a manufacturer take to ensure that energy loss in a transformer is minimized?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the winding of the transformer should be made of high resistance wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the core should be made of thin sheets of metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no magnetic material should be used to make the core</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the flux linking the primary with the secondary coils should be minimum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A transformer is a highly efficient device, but some energy is always lost during its operation. These losses are primarily due to two factors: copper loss (in the windings) and iron loss (in the core). <br/>  <br/> The manufacturer minimizes these losses through specific design choices: <br/>  <br/> Copper Loss: This is due to the heating effect of the current flowing through the resistance of the primary and secondary coils (I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R loss). It is minimized by using thick copper wire with a very low resistance. <br/>  <br/> Iron Loss: This loss occurs in the soft iron core. It consists of two parts: <br/>  <br/> Hysteresis Loss: Energy is lost as the magnetic domains in the core repeatedly realign with the alternating magnetic field. This is minimized by using a soft magnetic material like soft iron. <br/>  <br/> Eddy Current Loss: The changing magnetic flux in the core induces small circular currents called eddy currents. These currents generate heat, leading to energy loss. This is a major source of inefficiency. <br/>  <br/> To minimize eddy current loss, the transformer's core is made of thin, insulated sheets of metal (laminations) rather than a solid block. The insulating layers between the sheets significantly increase the electrical resistance in the path of the eddy currents, reducing their magnitude and the associated heat loss. <br/>  <br/> The other options are incorrect: high resistance wire would increase heat loss; a non-magnetic core would prevent the transformer from working efficiently; and minimum flux linkage would make the transformer useless.</div>", "topic": "ELECTROMAGNETIC FIELD: TRANSFORMERS"}, {"id": "objective>Physics>1990>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A substance has a half of 3 mins. After 6mins, the count rate was observed to be 400. What was its count rate at zero time?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2400</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The half-life of the substance is 3 minutes. After 6 minutes, the number of half-lives elapsed is: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">half-lives</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td></tr></table></div> <br/> After each half-life, the count rate halves. So, after 2 half-lives, the count rate is reduced to: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">initial</td><td style=\"text-align:center;\">count</td><td style=\"text-align:center;\">rate</td></tr></table></div> <br/> Let the initial count rate be R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>. After 6 minutes: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">400</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 400 × 4 = 1600 <br/>  <br/> Therefore, the count rate at zero time was 1600.</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>1990>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The photocell works on the principle of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">voltaic cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emission of electrons by incident radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emission of protons by incident electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photographic plate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A photocell, or photoelectric cell, is a device that converts light energy into electrical energy. Its operation is based on the photoelectric effect, a fundamental principle in quantum physics. <br/> When light (electromagnetic radiation) of a sufficiently high frequency strikes a photosensitive material, it transfers energy to the electrons in the material. If a single photon of light has enough energy to overcome the material's work function (the minimum energy required to eject an electron), it will knock an electron out of the surface. <br/>  <br/> The photocell uses this effect to generate a current. The light-sensitive material acts as a cathode. When light hits it, electrons are emitted and travel across a vacuum or a gas to an anode, which is positively charged. This flow of electrons constitutes an electric current that can be measured or used to power a circuit. <br/> The magnitude of this current is directly proportional to the intensity of the incident light, making photocells useful in various applications like streetlights, light meters in cameras, and burglar alarms.</div>", "topic": "ELEMENTARY MODERN PHYSICS : PHOTOELECTRIC EFFECTS"}, {"id": "objective>Physics>1990>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> What is the reading of the vernier scale above</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.88 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.80 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.28 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.97 cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- A vernier caliper has two scales: <br/>   1. <strong>Main Scale</strong>: Fixed scale with divisions in centimeters (cm) or millimeters (mm). <br/>   2. <strong>Vernier Scale</strong>: Movable scale that slides along the main scale. It has smaller divisions (usually 10 divisions that equal 9 mm on the main scale, giving a precision of 0.1 mm or 0.01 cm). <br/>  <br/> <strong>How to Read a Vernier Caliper:</strong> <br/> 1. <strong>Main Scale Reading (MSR):</strong>   <br/>    Read the value just before the zero mark of the vernier scale on the main scale. In this case, it is <strong>1.8 cm</strong>. This means the object is at least 1.8 cm long. <br/>  <br/> 2. <strong>Vernier Scale Reading (VSR):</strong>   <br/>    Look for the line on the vernier scale that aligns perfectly with any line on the main scale. The question states: <strong>\"there is no alignment on the Vernier scale with the main scale\"</strong>. This implies that the zero mark of the vernier scale is exactly coinciding with a main scale division. Therefore, the VSR is <strong>0</strong>. <br/>  <br/> 3. <strong>Total Reading:</strong>   <br/>    Total reading = MSR + (VSR × Least Count)   <br/>    - The least count of a vernier caliper is the smallest measurement it can make. For a common vernier caliper with 10 divisions on the vernier scale, the least count is <strong>0.01 cm</strong> (or 0.1 mm).   <br/>    - Since VSR = 0, the total reading is simply the main scale reading:   <br/>      <strong>1.8 cm + (0 × 0.01 cm) = 1.80 cm</strong>. <br/>  <br/> <strong>Why is it written as 1.80 cm?</strong> <br/> - The trailing zero indicates precision. Since the vernier caliper can measure up to 0.01 cm, we write the reading with two decimal places to reflect that precision. Thus, 1.8 cm becomes <strong>1.80 cm</strong>. <br/>  <br/> <strong>Summary:</strong> <br/> - Main Scale Reading (MSR) = 1.8 cm <br/> - Vernier Scale Reading (VSR) = 0 (because no other line except zero aligns) <br/> - Total Reading = 1.8 cm + 0 = <strong>1.80 cm</strong> <br/>  <br/> This means the object's length is exactly 1.80 cm, with no additional fraction from the vernier scale.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>1990>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Two horizontal forces, 10 N and 8 N and another force F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> inclined at 30° to the vertical acting as shown in the diagram above, keep the body P in equilibrium, The weight of the body is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> N</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The weight of the body will act vertically downward. <br/>  <br/> The weight, W, of the body = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>cos 30° <br/>  <br/> Resolving the horizontal components of the forces: <br/>  <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 8 + F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>sin 30° - 10 <br/>  <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 0.5F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - 2 <br/>  <br/> Since the body is at equilibrium, F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 0: <br/>  <br/> 0.5F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - 2 = 0 <br/>  <br/> 0.5F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />0.5</td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 4 N <br/>  <br/> So, <br/>  <br/> W = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>cos 30° <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">cos</td><td style=\"text-align:center;\">30°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />2</td></tr></table></div> <br/> ∴ W = 2&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> N</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>1990>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> What is the average velocity of the sprinter whose velocity time graph is as shown above</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">85.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.5 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.7 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Average</td><td style=\"text-align:center;\">velocity</td><td style=\"text-align:center;\">(speed)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Total distance covered<hr size=\"1\" />Total time taken</td></tr></table></div> <br/> Total distance covered = Area under the velocity time graph <br/>  <br/> Total time taken = 10 s <br/>  <br/> Total distance covered = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> × 2 × 10 + 10 × (8 - 2) + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> × (10 - 8) × 10 <br/>  <br/> Total distance covered = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> × 2 × 10 + 10 × 6 + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> × 2 × 10 <br/>  <br/> Total distance covered = 10 + 60 + 10 <br/>  <br/> Total distance covered = 80 m <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Average</td><td style=\"text-align:center;\">velocity</td><td style=\"text-align:center;\">(speed)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />10</td></tr></table></div> <br/> ∴ Average velocity (speed) = 8.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  <br/> So, the closest answer is 8.5 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>1990>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A force of 5 N act at a point Y on a rod XYZ as shown in the diagram above, if XY is 2 m. What is the moment of the force about point X?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0 Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7 Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 Nm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 5 N acts at point Y on a rod XYZ. <br/>  <br/> The distance XY is 2 m. <br/>  <br/> If the line of action of the force passes through point X (the pivot), then the perpendicular distance from X to the force is zero. <br/>  <br/> Thus, the moment about X is: <br/>  <br/> Moment = 5 N × 0 = 0 <br/>  <br/> <strong>Key Point:</strong> <br/> Even though the force is applied at point Y (which is 2 m from X), if the force is directed such that its line of action goes through X (e.g., along the rod toward X), the moment is zero. Only the component of the force perpendicular to the lever arm creates a moment.</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}];
